CREATE TABLE cites (
    cited_paper_id TEXT, -- example: ['100157', '100598'],
    citing_paper_id TEXT, -- example: ['100157', '364207'],
    PRIMARY KEY (cited_paper_id, citing_paper_id)
);

CREATE TABLE paper (
    paper_id TEXT, -- example: ['100157', '100598'],
    class_label TEXT, -- example: ['Agents', 'IR'],
    PRIMARY KEY (paper_id)
);

CREATE TABLE content (
    paper_id TEXT, -- example: ['100157', '100598'],
    word_cited_id TEXT, -- example: ['word1163', 'word1509'],
    PRIMARY KEY (paper_id, word_cited_id),
    CONSTRAINT fk_content_paper_id FOREIGN KEY (paper_id) REFERENCES paper (paper_id)
);

CREATE TABLE Question (
    questiontext TEXT, -- example: ['What is your age?', 'What is your gender?'],
    questionid INTEGER, -- example: [1, 2],
    PRIMARY KEY (questionid)
);

CREATE TABLE Survey (
    SurveyID INTEGER, -- example: [2014, 2016],
    Description TEXT, -- example: ['mental health survey for 2014', 'mental health survey for 2016'],
    PRIMARY KEY (SurveyID)
);

CREATE TABLE Answer (
    AnswerText TEXT, -- example: ['37', '44'],
    SurveyID INTEGER, -- example: [2014, 2016],
    UserID INTEGER, -- example: [1, 2],
    QuestionID INTEGER, -- example: [1, 2],
    PRIMARY KEY (UserID, QuestionID),
    CONSTRAINT fk_Answer_QuestionID FOREIGN KEY (QuestionID) REFERENCES Question,
    CONSTRAINT fk_Answer_SurveyID FOREIGN KEY (SurveyID) REFERENCES Survey
);

CREATE TABLE genre (
    id INTEGER, -- example: [1, 2],
    genre_name TEXT, -- example: ['Action', 'Adventure'],
    PRIMARY KEY (id)
);

CREATE TABLE game (
    id INTEGER, -- example: [44, 45],
    genre_id INTEGER, -- example: [4, 5],
    game_name TEXT, -- example: ['2 Games in 1: Sonic Advance & ChuChu Rocket!', '2 Games in 1: Sonic Battle & ChuChu Rocket!'],
    PRIMARY KEY (id),
    CONSTRAINT fk_game_genre_id FOREIGN KEY (genre_id) REFERENCES genre (id)
);

CREATE TABLE platform (
    id INTEGER, -- example: [1, 2],
    platform_name TEXT, -- example: ['Wii', 'NES'],
    PRIMARY KEY (id)
);

CREATE TABLE publisher (
    id INTEGER, -- example: [1, 2],
    publisher_name TEXT, -- example: ['10TACLE Studios', '1C Company'],
    PRIMARY KEY (id)
);

CREATE TABLE game_publisher (
    id INTEGER, -- example: [1, 2],
    game_id INTEGER, -- example: [10866, 9244],
    publisher_id INTEGER, -- example: [369, 328],
    PRIMARY KEY (id),
    CONSTRAINT fk_game_publisher_publisher_id FOREIGN KEY (publisher_id) REFERENCES publisher (id),
    CONSTRAINT fk_game_publisher_game_id FOREIGN KEY (game_id) REFERENCES game (id)
);

CREATE TABLE game_platform (
    id INTEGER, -- example: [1, 2],
    game_publisher_id INTEGER, -- example: [8564, 9852],
    platform_id INTEGER, -- example: [4, 7],
    release_year INTEGER, -- example: [2007, 2006],
    PRIMARY KEY (id),
    CONSTRAINT fk_game_platform_platform_id FOREIGN KEY (platform_id) REFERENCES platform (id),
    CONSTRAINT fk_game_platform_game_publisher_id FOREIGN KEY (game_publisher_id) REFERENCES game_publisher (id)
);

CREATE TABLE region (
    id INTEGER, -- example: [1, 2],
    region_name TEXT, -- example: ['North America', 'Europe'],
    PRIMARY KEY (id)
);

CREATE TABLE region_sales (
    region_id INTEGER, -- example: [1, 2],
    game_platform_id INTEGER, -- example: [50, 51],
    num_sales REAL, -- example: [3.5, 1.43],
    CONSTRAINT fk_region_sales_region_id FOREIGN KEY (region_id) REFERENCES region (id),
    CONSTRAINT fk_region_sales_game_platform_id FOREIGN KEY (game_platform_id) REFERENCES game_platform (id)
);

CREATE TABLE bool (
    name TEXT, -- example: ['neg', 'pos'],
    PRIMARY KEY (name)
);

CREATE TABLE person (
    name TEXT, -- example: ['student1', 'student10'],
    PRIMARY KEY (name)
);

CREATE TABLE disabled (
    name TEXT, -- example: ['student114', 'student125'],
    PRIMARY KEY (name),
    CONSTRAINT fk_disabled_name FOREIGN KEY (name) REFERENCES person (name)
);

CREATE TABLE enlist (
    name TEXT, -- example: ['student40', 'student51'],
    organ TEXT, -- example: ['fire_department', 'air_force'],
    CONSTRAINT fk_enlist_name FOREIGN KEY (name) REFERENCES person (name)
);

CREATE TABLE filed_for_bankrupcy (
    name TEXT, -- example: ['student122', 'student126'],
    PRIMARY KEY (name),
    CONSTRAINT fk_filed_for_bankrupcy_name FOREIGN KEY (name) REFERENCES person (name)
);

CREATE TABLE longest_absense_from_school (
    name TEXT, -- example: ['student1', 'student10'],
    month INTEGER, -- example: [0, 1],
    PRIMARY KEY (name),
    CONSTRAINT fk_longest_absense_from_school_name FOREIGN KEY (name) REFERENCES person (name)
);

CREATE TABLE male (
    name TEXT, -- example: ['student1', 'student101'],
