    CONSTRAINT fk_male_name FOREIGN KEY (name) REFERENCES person (name)
);

CREATE TABLE no_payment_due (
    name TEXT, -- example: ['student1', 'student10'],
    bool TEXT, -- example: ['neg', 'pos'],
    PRIMARY KEY (name),
    CONSTRAINT fk_no_payment_due_bool FOREIGN KEY (bool) REFERENCES bool (name),
